Greedy insertion with cost-based candidate evaluation and fallback expansion using time-window feasibility checks.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx       int
		deltaCost float64
		feasible  bool
	}
	orders := len(oris)
	for oi := 0; oi < orders; oi++ {
		candidates := make([]candidate, 0, dispatch.AssignsLen+1)
		bestIdx := -1
		bestDelta := 1e18
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			oldCost := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					candidates = append(candidates, candidate{idx: ai, deltaCost: delta, feasible: true})
					if delta < bestDelta {
						bestDelta = delta
						bestIdx = ai
					}
				}
				dispatch.Assigns[ai].RemoveShip(total_ship + oi)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		inserted := false
		if bestIdx != -1 {
			ok := dispatch.Assigns[bestIdx].AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				dispatch.Assigns[bestIdx].GenRoute()
				if dispatch.Assigns[bestIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestIdx].RemoveShip(total_ship + oi)
					dispatch.Assigns[bestIdx].GenRoute()
				}
			}
		}
		if !inserted {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+oi, oris[oi], dess[oi])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + oi)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

